class HybridWebView(
    private val context: Context,
    private val lifecycleOwner: LifecycleOwner,
    private val activityResultCaller: ActivityResultCaller,
    private val webAppBaseUrl: String,
    private val fileProviderAuthority: String,
    private val prefsName: String = "hybrid_webview_prefs",
    private val jsBridgeName: String = "NativeBridge"
) : DefaultLifecycleObserver {

    val webView: WebView = WebView(context)

    private val prefs: SharedPreferences =
        context.getSharedPreferences(prefsName, Context.MODE_PRIVATE)

    private val mainHandler = android.os.Handler(context.mainLooper)

    private var pendingCameraRequestId: String? = null
    private var pendingCameraFileUri: Uri? = null

    private val permissionLauncher: ActivityResultLauncher<Array<String>>
    private val cameraLauncher: ActivityResultLauncher<Intent>

    init {
        lifecycleOwner.lifecycle.addObserver(this)

        permissionLauncher =
            activityResultCaller.registerForActivityResult(
                ActivityResultContracts.RequestMultiplePermissions()
            ) { grants ->
                val granted = grants.values.all { it == true }
                if (!granted) {
                    emitToJs(
                        "camera.result",
                        JSONObject()
                            .put("ok", false)
                            .put("error", "PERMISSION_DENIED")
                            .put("requestId", pendingCameraRequestId ?: JSONObject.NULL)
                    )
                    pendingCameraRequestId = null
                    pendingCameraFileUri = null
                    return@registerForActivityResult
                }
                launchCameraInternal()
            }

        cameraLauncher =
            activityResultCaller.registerForActivityResult(
                ActivityResultContracts.StartActivityForResult()
            ) { result ->
                handleCameraResult(result)
            }

        configureWebView()
    }

    @SuppressLint("SetJavaScriptEnabled")
    private fun configureWebView() {
        val settings = webView.settings
        settings.javaScriptEnabled = true
        settings.domStorageEnabled = true
        settings.databaseEnabled = true
        settings.allowFileAccess = false
        settings.allowContentAccess = true
        settings.javaScriptCanOpenWindowsAutomatically = true
        settings.cacheMode = WebSettings.LOAD_DEFAULT
        settings.mixedContentMode = WebSettings.MIXED_CONTENT_COMPATIBILITY_MODE

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            settings.safeBrowsingEnabled = true
        }

        WebView.setWebContentsDebuggingEnabled(false)

        webView.webChromeClient = WebChromeClient()
        webView.webViewClient = object : WebViewClient() {
            override fun shouldOverrideUrlLoading(view: WebView, request: WebResourceRequest): Boolean {
                val url = request.url.toString()
                if (url.startsWith("http://") || url.startsWith("https://")) {
                    return false
                }
                return try {
                    context.startActivity(Intent(Intent.ACTION_VIEW, request.url).addFlags(Intent.FLAG_ACTIVITY_NEW_TASK))
                    true
                } catch (_: Exception) {
                    true
                }
            }

            override fun onPageFinished(view: WebView, url: String) {
                super.onPageFinished(view, url)
                emitToJs(
                    "native.ready",
                    JSONObject()
                        .put("ok", true)
                        .put("platform", "android")
                        .put("bridge", jsBridgeName)
                )
            }
        }

        webView.addJavascriptInterface(
            NativeBridge(context, this),
            jsBridgeName
        )
    }

    fun loadUrl(pathOrUrl: String) {
        val url = if (pathOrUrl.startsWith("http://") || pathOrUrl.startsWith("https://")) {
            pathOrUrl
        } else {
            webAppBaseUrl.trimEnd('/') + "/" + pathOrUrl.trimStart('/')
        }
        webView.loadUrl(url)
    }

    fun destroy() {
        lifecycleOwner.lifecycle.removeObserver(this)
        webView.removeJavascriptInterface(jsBridgeName)
        webView.stopLoading()
        webView.loadUrl("about:blank")
        webView.clearHistory()
        webView.removeAllViews()
        webView.destroy()
    }

    override fun onDestroy(owner: LifecycleOwner) {
        destroy()
    }

    @MainThread
    internal fun emitToJs(event: String, payload: JSONObject) {
        val safePayload = payload.toString()
        val js = """
            (function(){
              try {
                if (window && window.dispatchEvent) {
                  var detail = $safePayload;
                  window.dispatchEvent(new CustomEvent(${JSONObject.quote(event)}, { detail: detail }));
                }
                if (window && window.NativeEvents && typeof window.NativeEvents.onEvent === 'function') {
                  window.NativeEvents.onEvent(${JSONObject.quote(event)}, $safePayload);
                }
              } catch (e) {}
            })();
        """.trimIndent()
        mainHandler.post {
            webView.evaluateJavascript(js, null)
        }
    }

    internal fun requestCamera(requestId: String, optionsJson: String?) {
        pendingCameraRequestId = requestId
        val permissions = mutableListOf(Manifest.permission.CAMERA)
        if (Build.VERSION.SDK_INT <= Build.VERSION_CODES.P) {
            permissions += Manifest.permission.WRITE_EXTERNAL_STORAGE
        }

        val needs = permissions.any {
            ContextCompat.checkSelfPermission(context, it) != PackageManager.PERMISSION_GRANTED
        }

        if (needs) {
            permissionLauncher.launch(permissions.toTypedArray())
        } else {
            launchCameraInternal()
        }
    }

    private fun launchCameraInternal() {
        val requestId = pendingCameraRequestId ?: UUID.randomUUID().toString()
        pendingCameraRequestId = requestId

        val imageFile = createTempImageFile(context)
        val uri = FileProvider.getUriForFile(context, fileProviderAuthority, imageFile)
        pendingCameraFileUri = uri

        val intent = Intent(MediaStore.ACTION_IMAGE_CAPTURE).apply {
            putExtra(MediaStore.EXTRA_OUTPUT, uri)
            addFlags(Intent.FLAG_GRANT_WRITE_URI_PERMISSION)
            addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)
        }

        try {
            cameraLauncher.launch(intent)
        } catch (_: Exception) {
            emitToJs(
                "camera.result",
                JSONObject()
                    .put("ok", false)
                    .put("error", "LAUNCH_FAILED")
                    .put("requestId", requestId)
            )
            pendingCameraRequestId = null
            pendingCameraFileUri = null
        }
    }

    private fun handleCameraResult(result: ActivityResult) {
        val requestId = pendingCameraRequestId
        val uri = pendingCameraFileUri
        pendingCameraRequestId = null
        pendingCameraFileUri = null

        if (requestId == null) return

        if (result.resultCode != Activity.RESULT_OK || uri == null) {
            emitToJs(
                "camera.result",
                JSONObject()
                    .put("ok", false)
                    .put("error", "CANCELED")
                    .put("requestId", requestId)
            )
            return
        }

        emitToJs(
            "camera.result",
            JSONObject()
                .put("ok", true)
                .put("requestId", requestId)
                .put("uri", uri.toString())
        )
    }

    internal fun storageSet(key: String, value: String) {
        prefs.edit().putString(key, value).apply()
    }

    internal fun storageGet(key: String): String? {
        return prefs.getString(key, null)
    }

    internal fun storageRemove(key: String) {
        prefs.edit().remove(key).apply()
    }

    internal fun storageClear() {
        prefs.edit().clear().apply()
    }

    internal fun pushGetFcmToken(requestId: String) {
