                            .put("error", e.message ?: "UNKNOWN")
                    )
                }
        } catch (e: Exception) {
            emitToJs(
                "push.token",
                JSONObject()
                    .put("ok", false)
                    .put("requestId", requestId)
                    .put("error", e.message ?: "UNKNOWN")
            )
        }
    }

