    class NativeBridge(
        private val context: Context,
        private val host: HybridWebView
    ) {

        @JavascriptInterface
        fun ping(payloadJson: String?): String {
            return JSONObject()
                .put("ok", true)
                .put("payload", payloadJson ?: JSONObject.NULL)
                .toString()
        }

        @JavascriptInterface
        fun cameraCapture(requestId: String, optionsJson: String?) {
            host.requestCamera(requestId, optionsJson)
        }

        @JavascriptInterface
        fun storageSet(key: String, value: String) {
            host.storageSet(key, value)
        }

        @JavascriptInterface
        fun storageGet(key: String): String {
            val v = host.storageGet(key)
            return JSONObject()
                .put("ok", true)
                .put("key", key)
                .put("value", v ?: JSONObject.NULL)
                .toString()
        }

        @JavascriptInterface
        fun storageRemove(key: String) {
            host.storageRemove(key)
        }

        @JavascriptInterface
        fun storageClear() {
            host.storageClear()
        }

        @JavascriptInterface
        fun pushGetToken(requestId: String) {
