        }

        @JavascriptInterface
        fun pushSubscribeTopic(requestId: String, topic: String) {
            host.pushSubscribeToTopic(requestId, topic)
        }

        @JavascriptInterface
        fun pushUnsubscribeTopic(requestId: String, topic: String) {
            host.pushUnsubscribeFromTopic(requestId, topic)
        }

        @JavascriptInterface
        fun openExternalUrl(url: String) {
            try {
                val uri = Uri.parse(url)
                val intent = Intent(Intent.ACTION_VIEW, uri).addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                context.startActivity(intent)
            } catch (_: Exception) {
            }
        }
